    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        artifact, _ARTIFACT_REL_FIELDS, ArtifactRelationshipAttributes
    )
    return ArtifactNested(
        guid=artifact.guid,
        type_name=artifact.type_name,
        status=artifact.status,
        version=artifact.version,
        create_time=artifact.create_time,
        update_time=artifact.update_time,
        created_by=artifact.created_by,
        updated_by=artifact.updated_by,
        classifications=artifact.classifications,
        classification_names=artifact.classification_names,
        meanings=artifact.meanings,
        labels=artifact.labels,
        business_attributes=artifact.business_attributes,
        custom_attributes=artifact.custom_attributes,
        pending_tasks=artifact.pending_tasks,
        proxy=artifact.proxy,
        is_incomplete=artifact.is_incomplete,
        provenance_type=artifact.provenance_type,
        home_id=artifact.home_id,
        depth=artifact.depth,
        immediate_upstream=artifact.immediate_upstream,
        immediate_downstream=artifact.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


